import{_ as t,o,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"69D. Designated Work Groups","description":"","frontmatter":{"title":"69D. Designated Work Groups","eba":"Mental Health Services 2024-2028","topics":["consultation","union-matters","ohs","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/ohs/69D-designated-work-groups.md","filePath":"ebas/mental-health/common-terms/ohs/69D-designated-work-groups.md"}'),a={name:"ebas/mental-health/common-terms/ohs/69D-designated-work-groups.md"};function r(i,e,d,l,p,c){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_69d-designated-work-groups" tabindex="-1">69D. Designated Work Groups <a class="header-anchor" href="#_69d-designated-work-groups" aria-label="Permalink to &quot;69D. Designated Work Groups&quot;">​</a></h1><p><strong>(a)</strong> The Employer will establish and maintain a system of DWGs in consultation with Employees and where requested their Union/s.</p><p><strong>(b)</strong> In determining the particulars of DWGs (including number of HSRs), the following considerations will, where practicable, be taken into account:</p><p><strong>(i)</strong> the specific needs, conditions and hazards affecting Employees in the area(s) concerned</p><p><strong>(ii)</strong> the working arrangements, including shiftwork, of Employees in the area(s) concerned</p><p><strong>(iii)</strong> the accessibility of health and safety representatives to Employees in the area(s) concerned; and</p><p><strong>(iv)</strong> the geographical layout of the workplace.</p>',7)])])}const m=t(a,[["render",r]]);export{g as __pageData,m as default};
